1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with 3 neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
19	    const result = nextGeneration([
20	      [0, 0], [1, 0], [2, 0],
21	      [0, 1], [1, 1], [2, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it.todo("should bring a dead cell to life with exactly 3 neighbors (reproduction)");
27	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
28	  it.todo("should keep a 2x2 block as a still life");
29	  it.todo("should handle cells with negative coordinates");
30	});
31

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	export function nextGeneration(cells: Cell[]): Cell[] {
10	  const isLive = (x: number, y: number): boolean =>
11	    cells.some(([cx, cy]) => cx === x && cy === y);
12	
13	  const countLiveNeighbors = (x: number, y: number): number =>
14	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isLive(x + dx, y + dy)).length;
15	
16	  const survives = (neighbors: number): boolean =>
17	    neighbors === 2 || neighbors === 3;
18	
19	  return cells.filter(([x, y]) => survives(countLiveNeighbors(x, y)));
20	}
